def extract_text_blocks(content_blocks: list[dict[str, Any]]) -> str:
    parts: list[str] = []
    for block in content_blocks or []:
        block_type = block.get("type")
        if block_type in {"input_text", "output_text"}:
            text = block.get("text", "")
            if text:
                parts.append(text)
            continue
        parts.append(f"[{block_type or 'unknown-content'}]")
    return "\n\n".join(part for part in parts if part.strip()).strip()


def is_bootstrap_message(role: str, text: str) -> bool:
    if role != "user":
        return False
    stripped = text.lstrip()
    return stripped.startswith("# AGENTS.md instructions for ") or stripped.startswith(
        "<environment_context>"
    )


def build_stem(meta: dict[str, Any], session_path: Path) -> str:
    timestamp = str(meta.get("timestamp", ""))[:10] or "unknown-date"
    session_id = str(meta.get("id", ""))[:8] or session_path.stem[-8:]
    return f"{timestamp}-chat-transcript-{session_id}"


def render_markdown(export: dict[str, Any], raw_path: Path) -> str:
    meta = export["meta"]
    context = export["context"]
    session_path = export["session_path"]
    lines = [
        "# Codex 채팅 원문",
        "",
        "## 메타데이터",
        "",
        f"- session_id: `{meta.get('id', 'unknown')}`",
        f"- session_started_at: `{meta.get('timestamp', 'unknown')}`",
        f"- cwd: `{meta.get('cwd', 'unknown')}`",
        f"- source: `{meta.get('source', 'unknown')}`",
        f"- originator: `{meta.get('originator', 'unknown')}`",
        f"- model: `{context.get('model', 'unknown')}`",
        f"- original_jsonl: `{session_path}`",
        f"- archived_jsonl: `{raw_path}`",
        "",
        "## Transcript",
        "",
    ]

    if not export["messages"]:
        lines.append("- 추출된 message record가 없습니다.")
        lines.append("")
    else:
        for message in export["messages"]:
            label = message["role"]
            if message.get("phase"):
                label = f"{label} ({message['phase']})"
            lines.extend(
                [
                    f"### {label} · {message['timestamp'] or 'unknown'}",
                    "",
                    message["text"],
                    "",
                ]
            )

    if export["tools"]:
        lines.extend(["## Tool Records", ""])
        for tool in export["tools"]:
            title = tool["kind"]
            if tool.get("name"):
                title = f"{title}: {tool['name']}"
            lines.extend(
                [
                    f"### {title} · {tool['timestamp'] or 'unknown'}",
                    "",
                    "```json",
                    tool["summary"],
                    "```",
                    "",
                ]
            )

    return "\n".join(lines).rstrip() + "\n"


def truncate(text: str, limit: int) -> str:
    if len(text) <= limit:
        return text
    return text[: limit - 15] + "... [truncated]"


